          // Substatus from labels and workflow run data
          isTimeout: workflowRun?.conclusion === 'timed_out',
          gateType,
        }
      }),
    )

    // Filter by board if needed
    let filteredTasks = tasks
    if (board !== 'all') {
      if (board.startsWith('label:')) {
        const label = board.replace('label:', '')
        filteredTasks = tasks.filter((t) => t.labels.includes(label))
      } else if (board.startsWith('milestone:')) {
        // Would need to filter by milestone - for now just return all
        filteredTasks = tasks
      }
    }

    return NextResponse.json({ tasks: filteredTasks })
  } catch (error: any) {
    console.error('[Cody] Error fetching tasks:', error)

    // Check for rate limiting (403 from GitHub)
    const isRateLimited =
      error?.status === 403 ||
      error?.message?.includes('rate limit') ||
      error?.response?.headers?.['x-ratelimit-remaining'] === '0'

    if (isRateLimited) {
      const resetTime = error?.response?.headers?.['x-ratelimit-reset']
      const resetDate = resetTime ? new Date(parseInt(resetTime) * 1000) : null
      const retryAfter = resetDate
        ? Math.ceil((resetDate.getTime() - Date.now()) / 1000 / 60)
        : null

      return NextResponse.json(
        {
          error: 'rate_limited',
          message: 'GitHub API rate limit exceeded',
          retryAfter: retryAfter ? `${retryAfter} minutes` : 'unknown',
          resetTime: resetDate?.toISOString() || null,
        },
        { status: 429 },
      )
    }

    // Check for missing token - match both old and new error message formats from getOctokit()
    // Old: "GITHUB_TOKEN not configured"
    // New: "Neither CODY_BOT_TOKEN nor GITHUB_TOKEN is configured"
    // Both contain "TOKEN" and "configured"
    const isNoTokenError =
      error?.message?.includes('TOKEN') &&
      error?.message?.includes('configured') &&
      (error?.message?.includes('GITHUB_TOKEN') || error?.message?.includes('CODY_BOT_TOKEN'))

    if (isNoTokenError) {
      return NextResponse.json(
        {
          error: 'no_token',
          message:
            'GitHub token is not configured. Set CODY_BOT_TOKEN or GITHUB_TOKEN in environment variables.',
        },
        { status: 401 },
      )
    }

    // Return empty state for other errors instead of mock data
    return NextResponse.json({
      tasks: [],
      error: error?.message || 'Failed to fetch tasks',
    })
  }
}

export async function POST(req: NextRequest) {
  const authResult = await requireCodyAuth(req)
  if (authResult instanceof NextResponse) return authResult

  try {
    const body = await req.json()

    // Zod validation schema for task creation
    const createTaskSchema = z.object({
      title: z.string().min(1),
      body: z.string().optional(),
      labels: z.array(z.string()).optional(),
      assignees: z.array(z.string()).optional(),
      actorLogin: z.string().optional(),
      attachments: z.array(z.any()).optional(),
    })

    const validation = createTaskSchema.safeParse(body)
    if (!validation.success) {
      return NextResponse.json(
        { error: 'Invalid request', details: validation.error.issues },
        { status: 400 },
      )
    }

    const { title, body: issueBody, labels, assignees, attachments, actorLogin } = validation.data

    // Verify actorLogin matches the authenticated session (prevents impersonation)
    const actorResult = await verifyActorLogin(req, actorLogin)
    if (actorResult instanceof NextResponse) return actorResult
    const { identity } = actorResult

    // Use verified identity's login for attribution
    const verifiedLogin = identity.login

    if (!title) {
      return NextResponse.json({ error: 'Title is required' }, { status: 400 })
    }

    // Create the issue in GitHub - use verified login for attribution
    const actorNote = `\n\n---\n_Created by @${verifiedLogin} via Cody dashboard_`
    const issue = await createIssue({
      title,
      body: (issueBody || '') + actorNote,
      labels: labels || [],
      assignees: assignees || [],
    })

    console.log('[Cody] Created issue:', issue.number, issue.title)

    // Auto-trigger pipeline by commenting @cody on the issue
    try {
      await postComment(issue.number, '@cody')
      console.log('[Cody] Triggered pipeline for issue:', issue.number)
    } catch (triggerError: any) {
      console.error('[Cody] Failed to trigger pipeline:', triggerError.message)
      // Don't fail the whole request if trigger fails - task was still created
    }

    // Upload attachments if provided
    const uploadedAttachments = []
    if (attachments && Array.isArray(attachments) && attachments.length > 0) {
      console.log('[Cody] Uploading', attachments.length, 'attachments...')
      for (const attachment of attachments) {
        try {
          const result = await uploadIssueAttachment(issue.number, {
            name: attachment.name,
            content: attachment.content,
          })
          uploadedAttachments.push(result)
          console.log('[Cody] Uploaded attachment:', result.name, result.attachment_url)
        } catch (attachError: any) {
          console.error('[Cody] Failed to upload attachment:', attachError.message)
        }
      }
    }

    return NextResponse.json({
      success: true,
      issue: {
        number: issue.number,
        title: issue.title,
        html_url: issue.html_url,
      },
      attachments: uploadedAttachments,
    })
  } catch (error: any) {
    console.error('[Cody] Error creating task:', error)
    Sentry.captureException(error, { tags: { route: '/api/cody/tasks POST' } })
    return NextResponse.json(
      { error: 'Failed to create task', details: error.message },
      { status: 500 },
    )
  }
}

