  NEXT_PUBLIC_SERVER_URL: z.string().optional(),
  NEXT_PUBLIC_SENTRY_DSN: z.string().optional(),
})

/**
 * Validates all required environment variables.
 * Throws with a clear error message if any required variable is missing.
 * Logs warnings for missing optional variables (does not throw).
 */
export function validateEnv(): void {
  // Validate required environment variables
  const requiredResult = requiredServerEnvSchema.safeParse(process.env)

  if (!requiredResult.success) {
    const missingVars = requiredResult.error.issues.map((issue) => issue.path.join('.')).join(', ')
    throw new Error(
      `Missing required environment variables: ${missingVars}. Please set these in your .env file.`,
    )
  }

  // Validate optional environment variables (warn if missing, don't throw)
  const optionalResult = optionalServerEnvSchema.safeParse(process.env)

  if (!optionalResult.success) {
    const missingOptional = optionalResult.error.issues
      .filter((issue) => issue.code === 'invalid_type') // Only warn if explicitly set to wrong type
      .map((issue) => issue.path.join('.'))
      .join(', ')

    if (missingOptional) {
      console.warn(`[Env] Optional environment variables with invalid types: ${missingOptional}`)
    }
  }

  // Check for common optional vars that might be missing and log warnings
  const optionalVars = ['SENTRY_DSN', 'OPENAI_API_KEY', 'GEMINI_API_KEY', 'GITHUB_TOKEN']
  for (const varName of optionalVars) {
