      console.warn(
        `[Env] Optional environment variable ${varName} is not set. Some features may be disabled.`,
      )
    }
  }

  // Check for public vars (warn if missing)
  const publicVars = ['NEXT_PUBLIC_SERVER_URL', 'NEXT_PUBLIC_SENTRY_DSN']
  for (const varName of publicVars) {
    if (!process.env[varName]) {
      console.warn(`[Env] Public environment variable ${varName} is not set.`)
    }
  }
}

